        return None

    succ = [[] for _ in range(n)]
    pred_count = [0] * n
    pred_meta = [[] for _ in range(n)]

    def add_edge(a, b, typ, m=-1):
        succ[a].append((b, typ, m))
        pred_count[b] += 1
        pred_meta[b].append((a, typ, m))

