            k = next_op[j]
            m, p = jobs[j][k]
            s = max(job_ready[j], machine_ready[m])
            e = s + p
            starts[(j, k)] = s
            ends[(j, k)] = e
            sequences[m].append(j)
            job_ready[j] = e
            machine_ready[m] = e
