                elif rule == 6:
                    key = (ect, -rem, remaining_work[j][k + 1], p, j)
                else:
                    noise = rng.random() if rng is not None else 0.0
                    key = (ect + int(12 * noise), est, p + int(8 * noise), -rem, noise, j)

